"""matplotlib.cbook — utility functions and classes."""

import numpy as _np


class CallbackRegistry:
    def __init__(self, exception_handler=None, *, signals=None):
        self.callbacks = {}
        self._cid = 0

    def connect(self, signal, func):
        self._cid += 1
        self.callbacks.setdefault(signal, {})[self._cid] = func
        return self._cid

    def disconnect(self, cid):
        for signal in self.callbacks:
            self.callbacks[signal].pop(cid, None)

    def process(self, s, *args, **kwargs):
        for func in list(self.callbacks.get(s, {}).values()):
            try:
                func(*args, **kwargs)
            except Exception:
                pass

    def blocked(self, signal=None):
        import contextlib
        return contextlib.nullcontext()


class Grouper:
    def __init__(self, init=()):
        self._mapping = {}

    def join(self, a, *args):
        for b in args:
            self._mapping[id(b)] = id(a)

    def joined(self, a, b):
        return id(a) == id(b)

    def get_siblings(self, a):
        return [a]


class silent_list(list):
    def __init__(self, type_name, seq=None):
        self.type = type_name
        super().__init__(seq or [])

    def __repr__(self):
        return f'<silent_list of {len(self)} {self.type}>'


def flatten(seq, scalarp=None):
    for item in seq:
        if hasattr(item, '__iter__') and not isinstance(item, str):
            yield from flatten(item, scalarp)
        else:
            yield item


def is_scalar_or_string(val):
    return isinstance(val, str) or not hasattr(val, '__iter__')


def _reshape_2D(X, name):
    X = _np.atleast_1d(X)
    if X.ndim == 1:
        return [X]
    return [X[:, i] for i in range(X.shape[1])]


def sanitize_sequence(data):
    if isinstance(data, _np.ndarray):
        return data.tolist()
    if hasattr(data, '__iter__') and not isinstance(data, str):
        return list(data)
    return [data]


def normalize_kwargs(kw, alias_mapping=None):
    return dict(kw) if kw else {}


def safe_masked_invalid(x, copy=False):
    return _np.asarray(x)


def boxplot_stats(X, whis=1.5, bootstrap=None, labels=None, autorange=False):
    result = []
    X = _reshape_2D(X, 'X')
    for xi in X:
        xi = _np.asarray(xi, dtype=float)
        xi = xi[~_np.isnan(xi)]
        if len(xi) == 0:
            result.append({})
            continue
        q1, med, q3 = _np.percentile(xi, [25, 50, 75])
        iqr = q3 - q1
        lo = q1 - whis * iqr
        hi = q3 + whis * iqr
        result.append({
            'mean': _np.mean(xi), 'med': med, 'q1': q1, 'q3': q3,
            'iqr': iqr, 'whislo': max(xi[xi >= lo].min(), lo) if len(xi[xi >= lo]) else lo,
            'whishi': min(xi[xi <= hi].max(), hi) if len(xi[xi <= hi]) else hi,
            'fliers': xi[(xi < lo) | (xi > hi)],
        })
    return result


def pts_to_prestep(x, *args):
    return (x,) + args


def pts_to_poststep(x, *args):
    return (x,) + args


def pts_to_midstep(x, *args):
    return (x,) + args


def get_sample_data(fname, asfileobj=True, *, np_load=False):
    return _np.array([])


def to_filehandle(fname, flag='r', return_opened=False, encoding=None):
    return open(fname, flag, encoding=encoding)


def _check_1d(x):
    return _np.atleast_1d(x)
